487	  async getItemInfo() {
488	    if (!this.itemData || !this.itemData[0]) {
489	      return;
490	    }
491	
492	    const currentItem = this.itemData[0];
493	    const isOldItem = currentItem.is_item_old === true;
494	    this.applyProductAssignmentsFromItem(currentItem.productUserAssignments || []);
495	
496	
497	    const isSpruceNonLic = currentItem.div_code_fk === 9;
498	
499	    // Helper function to select based on item age
500	    const selectOption = (options, codeKey, idKey, applyYearCheck = false) => {
501	      return options.find((x) =>
502	        isOldItem
503	          ? x.mg_code === currentItem[codeKey] &&
504	          !x.is_active &&
505	          (!applyYearCheck || x.created_year !== 2025)
506	          : x.id === currentItem[idKey]
507	      );
508	    };
509	
510	    // Merchgroup selections
511	    this.selectedProductType = selectOption(this.productTypeOptions, "udf_merchgroup01", "udf_merchgroup01_id", true);
512	    this.selectedProductSubType = selectOption(this.productSubTypeOptions, "udf_merchgroup02", "udf_merchgroup02_id", true);
