4	  phase: string;
5	  status?: string | null;
6	  date?: string | null;
7	  completionDate?: string | null;
8	  estStartDate?: string | null;
9	  estCompletionDate?: string | null;
10	  neededDate?: string | null;
11	  detailLines?: string[];
12	  events?: LicensingStageEvent[];
13	  isDelayed?: boolean;
14	}
15	
16	interface LicensingStageEvent {
17	  status: string;
18	  label: string;
19	  date?: string | null;
20	}
21	
22	@Component({
23	  selector: 'app-licensing-stage-tracker',
24	  templateUrl: './licensing-stage-tracker.component.html',
25	  styleUrls: ['./licensing-stage-tracker.component.scss'],
26	  standalone: false
27	})
28	export class LicensingStageTrackerComponent implements OnChanges {
29	  @Input() stages: LicensingStageRow[] = [];
30	  @Input() itemNumber: string | null = null;
31	
32	  processedStages: any[] = [];
33	  expandedStagePhases = new Set<string>();
34	  overallProgress = 0;
35	
36	  private readonly stageOrder = [
37	    { phase: 'Submission', icon: 'S' },
38	    { phase: 'Resubmission', icon: 'R' },
39	    { phase: 'PPS Approval', icon: 'PPS' }
40	  ];
41	
42	  ngOnChanges(changes: SimpleChanges): void {
43	    if (changes['stages']) {
44	      this.processStages();
45	    }
46	  }
47	
48	  private processStages(): void {
49	    const byPhase = new Map((this.stages || []).map(stage => [stage.phase, stage]));
50	
51	    this.processedStages = this.stageOrder.map(stageDef => {
52	      const source = byPhase.get(stageDef.phase);
53	      const status = source?.status || 'Pending';
54	      const isComplete = this.isComplete(status);
55	      const isFailed = this.isFailed(status);
56	      const isRevisionState = this.isRevisionState(status);
57	      const isDelayed = !!source?.isDelayed;
58	      const displayDate = source?.completionDate || source?.date || source?.estCompletionDate || source?.estStartDate || null;
59	      const hasEvents = !!source?.events?.length;
60	
61	      return {
62	        ...source,
63	        phase: stageDef.phase,
64	        icon: stageDef.icon,
65	        status,
66	        isComplete,
67	        isFailed,
68	        isRevisionState,
69	        isDelayed,
70	        isPending: !source || (!isComplete && !isFailed && !isRevisionState),
71	        isCurrent: false,
72	        hasEvents,
73	        isExpanded: hasEvents && this.expandedStagePhases.has(stageDef.phase),
74	        displayDate,
75	        dateLabel: source?.completionDate ? 'Complete' : source?.date ? 'Start' : source?.estCompletionDate ? 'Est.' : source?.estStartDate ? 'Est. Start' : '',
76	        tooltip: this.buildTooltip(source, status)
77	      };
78	    });
79	
80	    const ppsStage = this.processedStages.find(stage => stage.phase === 'PPS Approval');
81	    if (ppsStage?.isComplete) {
82	      this.processedStages = this.processedStages.map(stage => ({
83	        ...stage,
84	        isComplete: true,
85	        isPending: false,
86	        isCurrent: false
87	      }));
88	    }
89	
90	    const firstActive = this.processedStages.findIndex(stage => !stage.isComplete && !stage.isFailed);
91	    if (firstActive >= 0) {
92	      this.processedStages[firstActive].isCurrent = true;
93	      this.processedStages[firstActive].isPending = false;
94	    }
95	
96	    const completed = this.processedStages.filter(stage => stage.isComplete).length;
97	    this.overallProgress = this.processedStages.length
98	      ? Math.round((completed / this.processedStages.length) * 100)
99	      : 0;
100	  }

